    long long tmp = (s - x + 2) * (s - x + 1) / 2;
    if (s - x - (a + x + 1 - b) >= 0)
      tmp -= (s - x - (a + x + 1 - b) + 2) * (s - x - (a + x + 1 - b) + 1) / 2;
    if (s - x - (a + x + 1 - c) >= 0)
