void dfs(int u, int p) {
  visited[u] = true;
  tin[u] = low[u] = timer++;
  int child = 0;
  for (int v : adj[u]) {
    if (p == v) {
      continue;
    } else if (visited[v]) {
      low[u] = min(tin[v], low[u]);
    } else {
      child++;
      dfs(v, u);
      low[u] = min(low[u], low[v]);
      if (low[v] >= tin[u] && p != -1) {
        a_points.insert(u);
      }
    }
  }
  if (child > 1 && p == -1) {
    a_points.insert(u);
  }
}
