  return true;
}
void solve() {
  cin >> n >> p;
  long long sum = 0;
  for (long long i = 1; i <= n; ++i) {
    cin >> a[i] >> b[i];
    can[i] = (long double)b[i] / (long double)a[i];
    sum += a[i];
  }
  if (p >= sum) {
    cout << -1 << '\n';
    return;
  }
  long double l = -EPS, r = 1e14 + EPS;
  for (int i = 1; i <= 500; ++i) {
    long double m = (l + r) / 2;
    if (check(m))
      l = m;
    else
      r = m;
  }
  cout << fixed << setprecision(9) << l << '\n';
}
