void tree_dp(int x, int father) {
  rt[x] = rt[father], sz[x] = 1;
  for (auto v : e[x]) {
    if (v == father) continue;
    tree_dp(v, x);
    sz[x] += sz[v];
    g[x] += g[v];
  }
  g[x] += sz[x];
}
void Tree_dp(int x, int father, int all) {
  upmax(mx, all);
  for (auto v : e[x]) {
    if (v == father) continue;
    Tree_dp(v, x, all + n - sz[v] - sz[v]);
  }
}
