    ModInt a = *this, r = 1;
    while (t) {
      if (t & 1) r *= a;
      a *= a;
      t >>= 1;
    }
    return r;
  }
  ModInt inv() const {
    ll a = x;
    ll b = mod;
    ll c = 1, d = 0;
    while (b) {
      ll t = a/b;
      a -= t*b; swap(a, b);
      c -= t*d; swap(c, d);
    }
    c %= mod;
    if (c < 0) c += mod;
    return c;
  }
  ModInt& operator/=(const ModInt a) { return (*this) *= a.inv(); }
  ModInt operator/(const ModInt a) const { return ModInt(*this)/=a; }
  bool operator==(const ModInt a) const { return x == a.x; }
  bool operator!=(const ModInt a) const { return x != a.x; }
