pair<int, int> a_reva(int a) {
  int g = gcm(a, rev[a]);
  int b = a / g;
  int c = rev[a] / g;
  return make_pair(b, c);
}
pair<int, int> invert_pint(pair<int, int> t) {
  return make_pair(t.second, t.first);
}
