bool prim(long long x) {
  if (x == 1ll || x == 4ll) return false;
  if (x <= 5ll) return true;
  int m = (int)sqrt(x);
  if (x % 6 != 1 && x % 6 != 5) return false;
  for (int i = 5; i <= m; i += 6) {
    if ((x % i == 0) || (x % (i + 2) == 0)) return false;
  }
  return true;
}
bool pr[10000000];
void prime(int n) {
  pr[1] = true;
  for (int i = 2; i <= n; i++) {
    if (!pr[i]) {
      for (int j = 2; j * i <= n; j++) {
        pr[i * j] = true;
      }
    }
  }
}
