      else
        b = (x4 - x3 + 1) * (y4 - y3 + 1) / 2;
    }
    sum_a += a;
    sum_a -= b;
    sum_b -= a;
    sum_b += b;
    long long tmpx = max(x1, x3);
    long long tmpy = max(y1, y3);
    long long tmpxx = min(x2, x4);
    long long tmpyy = min(y2, y4);
    if (tmpx > tmpxx || tmpy > tmpyy) {
