}
void upToRight(long long ans, int i, int n, long long t) {
  ans += t * sumaR[i + 1] + sar[i + 1] + (t + n - i) * sumbR[i] - sbl[i - 1] +
         sbl[n] - sumbL[i - 1] * (n - i + 1);
  res = max(res, ans);
}
