    for (int j = 0; j < n; j++) {
      if (vec2[i][j].x != now) {
        now = vec2[i][j].x;
        cnt++;
        if (j) put(cnt - 1, cnt, 1);
      }
      int y = ID[go(vec2[i][j].id, i)];
      put(cnt, y, 0);
      put(y, cnt, 0);
    }
  }
  for (int i = 1; i <= cnt; i++)
