  for (int i = head[x]; i; i = Next[i]) {
    int y = to[i];
    if (y == f || vis[y]) continue;
    d[y] = d[x] + 1;
    fa[y] = x;
    vis[y] = 1;
    dfs_tree(y, x);
    size[x] += size[y];
  }
}
int main() {
