        pos = i;
        while (pos != fa[p2]) {
          a[cnt].push_back(pos);
          pos = fa[pos];
        }
      } else if (c3 > 3 && c3 % 3 != 0) {
        cnt++;
        pos = p1;
        while (pos != fa[p2]) {
          a[cnt].push_back(pos);
          pos = fa[pos];
        }
        a[cnt].push_back(i);
