    for (int j = 0; j < i; j++) {
      long long mask = 0;
      for (int k = 0; k < m; k++) mask |= (s[i][k] == s[j][k]) << k;
      w[mask] |= 1LL << i | 1LL << j;
    }
  }
  for (int i = (1 << m) - 1; i >= 0; i--)
    for (int j = 0; j < m; j++)
      if (i & 1 << j) w[i ^ 1 << j] |= w[i];
  for (int i = 0; i < (1 << m); i++) cnt[i] = __builtin_popcountll(w[i]);
  for (int i = (1 << m) - 1; i >= 0; i--) {
    if (!cnt[i]) continue;
    double sum = 0;
    for (int j = 0; j < m; j++)
      if (~i & 1 << j) sum += dp[i | 1 << j] * cnt[i | 1 << j];
    dp[i] = 1 + sum / (m - __builtin_popcount(i)) / cnt[i];
  }
  printf("%.18lf\n", dp[0]);
  return 0;
