  if (a > x && c > x) return f(a - x, b - x, c - x, d - x, n);
  if (c > x) return f(a, b, c - x, d - x, n);
  return max(b - c + 1, max(f(a, b, c, x - 1, n), f(a, b, x + 1, d, n)));
}
