  int to, next, f, v;
} e[2010000];
void add1(int o, int p, int q, int w) {
  e[++size].to = p, e[size].next = g[o], g[o] = size, e[size].f = q,
  e[size].v = w;
}
void add(int o, int p, int q, int w) { add1(o, p, q, w), add1(p, o, 0, -w); }
