    a[i].t += a[i].s;
    ex[++cnt] = a[i].s, ex[++cnt] = a[i].t;
  }
  init();
  S = 0, T = tot + 1;
  for (i = 0; i <= tot; i++) add(i, i + 1, k, 0);
  for (i = 1; i <= n; i++) add(a[i].s, a[i].t, 1, a[i].val), num[i] = size - 1;
