    for (int j = 0; j < m; j++) {
      if (buf[i][j] == 'S')
        sy = i, sx = j;
      else if (buf[i][j] == 'B')
        T[pt] = 0, pos[pt] = vt(i, j), pt++;
      else if ('1' <= buf[i][j] && buf[i][j] <= '8')
        T[pt] = 1, oldi[pt] = buf[i][j] - '1', pos[pt] = vt(i, j), pt++, tr++;
    }
  }
  for (int i = 0; i < tr; i++) scanf("%d", &C[i]);
  assert(sx != -1);
  BFS(sy, sx);
