template <typename _T>
class vertix {
 private:
  int capacity = 0;
  _T* arr = new _T[capacity];

 public:
  vertix() {
    capacity = 000;
    delete[] arr;
    arr = new _T[capacity];
  }
  vertix(int S) {
    capacity = S;
    delete[] arr;
    arr = new _T[capacity];
  }
  _T& operator[](int index) { return arr[index]; }
  int size() { return capacity; }
  void push_back(_T type) {
    _T* newarr = new _T[capacity + 1];
    for (int i = 0; i < capacity; i++) {
      newarr[i] = arr[i];
    }
    newarr[capacity] = type;
    delete[] arr;
    arr = newarr;
    capacity++;
  }
  void push_front(_T type) {
    _T* newarr = new _T[capacity + 1];
    for (int i = 1; i < capacity + 1; i++) {
      newarr[i] = arr[i - 1];
    }
    newarr[0] = type;
    capacity++;
    delete[] arr;
    arr = newarr;
  }
  void pop_front() {
