const int SIZE = 1e6 + 10;
struct Union_Find {
  int d[SIZE], num[SIZE];
  void init(int n) {
    for (int i = 0; i < (n); ++i) d[i] = i, num[i] = 1;
  }
  int find(int x) {
    int y = x, z = x;
    while (y != d[y]) y = d[y];
    while (x != y) {
      x = d[x];
      d[z] = y;
      z = x;
    }
    return y;
  }
  bool is_root(int x) { return d[x] == x; }
  bool uu(int x, int y) {
    x = find(x);
    y = find(y);
    if (x == y) return 0;
    if (num[x] > num[y]) swap(x, y);
    num[y] += num[x];
    d[x] = y;
    return 1;
  }
