        vz[l + 1] = max(vz[l + 1], dp[j][l] + modd(z - j + p));
      }
    }
    for (int i = 0; i < 55; i++) dp[z][i] = max(dp[z][i], vz[i]);
  }
  cout << dp[z][k] << '\n';
