struct DSU {
  void init(int n) {
    for (int i = 0, _a = (n + 1); i < _a; ++i) lab[i] = -1;
  }
  int getRoot(int u) {
    if (lab[u] < 0) return u;
    return lab[u] = getRoot(lab[u]);
  }
  bool merge(int u, int v) {
    u = getRoot(u);
    v = getRoot(v);
    if (u == v) return false;
    if (lab[u] > lab[v]) swap(u, v);
    lab[u] += lab[v];
    lab[v] = u;
    return true;
  }
};
