        fix(node, edg, pos, st, en, str);
        int spos = fipos[edg] + pos - 1;
        if (spos >= slen) {
          break;
        }
        if (s[spos] == str[st + depth[node] + pos - 1]) {
          en++;
          pos++;
          fix(node, edg, pos, st, en, str);
        } else {
          break;
        }
      }
      if (en == st + l) {
        if (done.find({node, {edg, pos}}) == done.end()) {
