    prefix[i][1] = sum[i][1] + prefix[i - 1][1];
  }
  for (int i = 1; i <= m; i++) {
    min1 = 1e6 + 5;
    min2 = 1e6 + 5;
    for (int j = x; j <= y; j++) {
      if (i - j < 0)
