        if (min1 > dp[i][0]) min1 = dp[i][0];
        dp[i][1] = dp[i - j][0] + (prefix[i][1] - prefix[i - j][1]);
        if (min2 > dp[i][1]) min2 = dp[i][1];
      }
    }
    dp[i][0] = min1;
    dp[i][1] = min2;
  }
