  flag++;
  queue<pair<int, int>> q;
  vis[a] = flag;
  cnt[a]++;
  q.push({a, 0});
  while (not q.empty()) {
    int u = q.front().first;
    int d = q.front().second;
    q.pop();
    int v[2] = {u / 2, 2 * u};
    for (int i = 0; i < 2; i++) {
      if (v[i] < 0 or v[i] >= MAXN) continue;
      if (vis[v[i]] == flag) continue;
      vis[v[i]] = flag;
      cnt[v[i]]++;
      cost[v[i]] += d + 1;
      q.push({v[i], d + 1});
    }
  }
}
