    long long ret = 0;
    for (int i = 0; i < cnt; i++) {
        ret += c[k[i]];
    }
    for (int i = cnt; i < n; i++) {
        ret += c[i - cnt];
        if (i - cnt > k[i]) {
            return 0;
        }
    }

    return ret;
}

