    scanf("%d%d", &n, &m);
    for (int i = 0; i < n; i++) {
        scanf("%d", k + i);
        k[i]--;
    }
    for (int i = 0; i < m; i++) {
        scanf("%d", c + i);
    }
    sort(k, k + n);

    int lo = -1, hi = n;
    while (lo + 1 < hi) {
        int mid = (lo + hi) / 2;
        long long res = check(mid);
        // fprintf(stderr, "check(%d) = %lld\n", mid, res);
        if (res) {
            hi = mid;
        } else {
            lo = mid;
