  for (int i = (1); i <= (C); i++) {
    ans[color[rt][i - 1]] = i;
    pset.insert(i);
  }
  done[rt] = 1;
  que.push(rt);
  while (!que.empty()) {
    int u = que.front();
    que.pop();
    for (auto it : color[u]) ban[it] = 1;
    for (auto v : E[u]) {
      if (done[v]) continue;
