  if (st == l && ed == r) {
    seg[i].mx += av;
    seg[i].ad += av;
    return;
  }
  int m = (l + r) / 2;
  if (m <= st)
    s_add(i * 2 + 2, m, r, st, ed, av);
  else if (m >= ed)
    s_add(i * 2 + 1, l, m, st, ed, av);
  else {
    s_add(i * 2 + 1, l, m, st, m, av);
    s_add(i * 2 + 2, m, r, m, ed, av);
  }
  seg[i].mx = max(seg[2 * i + 1].mx, seg[2 * i + 2].mx) + seg[i].ad;
}
