    if (acc[i] > 1) {
      i += acc[i];
      continue;
    }
    while (acc[j] == 1) j++;
    j--;
    ret = max(ret, solve(max(0, i - 1), min(n - 1, j + 1)));
    i = j + 1;
  }
  cout << ret << endl;
  for (int i = 0; i < n; i++) printf("%d ", v[i]);
  printf("\n");
