        for (; b > 0; b--) s += '1';
        s += '0';
        a--;
        for (; a > 0; a--) s = '0' + s;
      }
    }
    for (int i = 0; i < a; i++) {
      s = '0' + s;
    }
    for (int i = 0; i < b; i++) {
