      k++;
      a[k] = v[i];
    }
  for (i = st; i <= dr; i++) v[i] = a[i];
}
void mergesort(int st, int dr) {
  if (st < dr) {
    int m = (dr + st) / 2;
    mergesort(st, m);
    mergesort(m + 1, dr);
    interclasare(st, dr, m);
  }
}
